-- ============================================================
-- CES SAVINGS COLUMN MAP - V2
-- Adds index-based mapping + fuzzy threshold columns
-- Seed data with exact column indexes from screenshots
-- ============================================================

-- ============================================================
-- STEP 1: ALTER TABLE - add new columns
-- ============================================================

-- EXCEL_COL_POSITION already exists - just ensure it's there
-- If it doesn't exist uncomment this:
-- ALTER TABLE CES_SAVINGS_COLUMN_MAP ADD EXCEL_COL_POSITION NUMBER;

-- Add fuzzy threshold column
ALTER TABLE CES_SAVINGS_COLUMN_MAP
    ADD FUZZY_THRESHOLD NUMBER(5,2) DEFAULT 75;

-- Add expected row1/row2 columns for confidence bonus
ALTER TABLE CES_SAVINGS_COLUMN_MAP
    ADD ROW1_EXPECTED VARCHAR2(500);

ALTER TABLE CES_SAVINGS_COLUMN_MAP
    ADD ROW2_EXPECTED VARCHAR2(500);

COMMENT ON COLUMN CES_SAVINGS_COLUMN_MAP.EXCEL_COL_POSITION IS
    'PRIMARY lookup key. 1-based column index from Excel. Guaranteed by stakeholder column order agreement.';
COMMENT ON COLUMN CES_SAVINGS_COLUMN_MAP.FUZZY_THRESHOLD IS
    'Minimum fuzzy match score for row3 header validation. Default 75. Lower = more lenient.';
COMMENT ON COLUMN CES_SAVINGS_COLUMN_MAP.ROW1_EXPECTED IS
    'Expected row1 header for confidence bonus scoring (5 pts). Unreliable due to merged cells.';
COMMENT ON COLUMN CES_SAVINGS_COLUMN_MAP.ROW2_EXPECTED IS
    'Expected row2 header for confidence bonus scoring (5 pts). Unreliable due to merged cells.';


-- ============================================================
-- STEP 2: UPDATE existing rows with indexes + expected headers
