-- ============================================================
-- VERIFICATION
-- ============================================================
SELECT
    SHEET_NAME,
    COUNT(*)                                              AS TOTAL,
    SUM(CASE WHEN EXCEL_COL_POSITION IS NOT NULL THEN 1 ELSE 0 END) AS WITH_INDEX,
    SUM(CASE WHEN EXCEL_COL_POSITION IS NULL     THEN 1 ELSE 0 END) AS WITHOUT_INDEX
FROM CES_SAVINGS_COLUMN_MAP
GROUP BY SHEET_NAME
ORDER BY SHEET_NAME;
